context__Hooks.body:
export interface Hooks {
  render: () => void;
  sync: () => void;
  renderInspector: () => void;
  drawMinimap: () => void;
  applyCam: () => void;
  persist: () => void;
  pushHistory: () => void;
  updateUndoButtons: () => void;
  toast: (msg: string) => void;
  showTab: (which: 'insp' | 'style' | 'mmd' | 'source' | 'nav' | 'slice') => void;
  /** refresh the navigator pane list */
  renderNavigator: () => void;
  /** refresh the slice pane (neighbourhood mmd) */
  renderSlice: () => void;
  /** recompute obstacle-avoiding wire routes, then re-render */
  reroute: () => void;
  /** re-route ONLY these edge ids (incremental), then re-render */
  rerouteEdges: (ids: Set<string>) => void;
  /** redraw wires + edge labels only; does NOT rebuild node DOM */
  redrawWires: () => void;
  /** live-drag: re-path only edges incident to these moved nodes, in place */
  redrawWiresFor: (ids: Set<string>) => void;
  /** drill into a node: show only its internal level */
  enterContainer: (id: string) => void;
}

diff__DiffInput.body:
export interface DiffInput {
  nodes: Record<string, DiagramNode>;
  edges: DiagramEdge[];
}

diff__NodeChange.body:
export interface NodeChange {
  id: string;
  field: string;   // which attribute differs (label | shape | kind | fm)
  before: string;
  after: string;
}

diff__MmdDiff.body:
export interface MmdDiff {
  addedNodes: string[];
  removedNodes: string[];
  changedNodes: NodeChange[];
  addedEdges: string[];     // "from->to:style"
  removedEdges: string[];
  counts: {
    nAdd: number; nRem: number; nChg: number;
    eAdd: number; eRem: number;
    nUnchanged: number; eUnchanged: number;
  };
}

diff__edgeKey.body:
export function edgeKey(e: DiagramEdge): string {
  return `${e.from}->${e.to}:${e.style}`;
}

diff__fmSig.body:
function fmSig(fm?: Frontmatter): string {
  if (!fm) return '';
  const ifaces = (fm.interfaces ?? [])
    .map((i) => `${i.name}(${(i.accepts ?? []).join(',')})->(${(i.returns ?? []).join(',')})`)
    .join('|');
  return `${fm.name}\u00a7${fm.description}\u00a7${(fm.state ?? []).join(',')}\u00a7${ifaces}`;
}

diff__diffModels.body:
export function diffModels(before: DiffInput, after: DiffInput): MmdDiff {
  const bN = before.nodes, aN = after.nodes;
  const bIds = Object.keys(bN), aIds = Object.keys(aN);
  const bSet = new Set(bIds), aSet = new Set(aIds);

  const addedNodes = aIds.filter((id) => !bSet.has(id)).sort();
  const removedNodes = bIds.filter((id) => !aSet.has(id)).sort();

  const changedNodes: NodeChange[] = [];
  let nUnchanged = 0;
  for (const id of aIds) {
    if (!bSet.has(id)) continue;           // added, handled above
    const b = bN[id], a = aN[id];
    const fields: [string, string, string][] = [
      ['label', b.label ?? '', a.label ?? ''],
      ['shape', b.shape ?? '', a.shape ?? ''],
      ['kind', (b.kind ?? '') as string, (a.kind ?? '') as string],
      ['fm', fmSig(b.fm), fmSig(a.fm)],
    ];
    let changed = false;
    for (const [field, bv, av] of fields) {
      if (bv !== av) { changedNodes.push({ id, field, before: bv, after: av }); changed = true; }
    }
    if (!changed) nUnchanged++;
  }
  changedNodes.sort((x, y) => x.id.localeCompare(y.id) || x.field.localeCompare(y.field));

  // edges by stable key
  const bEdges = new Map<string, DiagramEdge>();
  const aEdges = new Map<string, DiagramEdge>();
  for (const e of before.edges) bEdges.set(edgeKey(e), e);
  for (const e of after.edges) aEdges.set(edgeKey(e), e);

  const addedEdges: string[] = [];
  const removedEdges: string[] = [];
  let eUnchanged = 0;
  for (const k of aEdges.keys()) {
    if (bEdges.has(k)) eUnchanged++; else addedEdges.push(k);
  }
  for (const k of bEdges.keys()) {
    if (!aEdges.has(k)) removedEdges.push(k);
  }
  addedEdges.sort();
  removedEdges.sort();

  return {
    addedNodes, removedNodes, changedNodes, addedEdges, removedEdges,
    counts: {
      nAdd: addedNodes.length,
      nRem: removedNodes.length,
      nChg: new Set(changedNodes.map((c) => c.id)).size,
      eAdd: addedEdges.length,
      eRem: removedEdges.length,
      nUnchanged,
      eUnchanged,
    },
  };
}

frontmatter__emptyInterface.body:
export function emptyInterface(): NodeInterface {
  return { name: '', accepts: [], returns: [] };
}

frontmatter__emptyFrontmatter.body:
export function emptyFrontmatter(): Frontmatter {
  return { name: '', description: '', state: [], interfaces: [] };
}

frontmatter__normalizeFrontmatter.body:
export function normalizeFrontmatter(raw: unknown): Frontmatter {
  const out = emptyFrontmatter();
  if (!raw || typeof raw !== 'object') return out;
  const fm = raw as Record<string, unknown>;
  if (typeof fm.name === 'string') out.name = fm.name;
  if (typeof fm.description === 'string') out.description = fm.description;
  if (Array.isArray(fm.state)) out.state = fm.state.slice();
  if (Array.isArray(fm.interfaces)) {
    out.interfaces = (fm.interfaces as unknown[]).map((i) => {
      const iface = (i ?? {}) as Record<string, unknown>;
      return {
        name: typeof iface.name === 'string' ? iface.name : '',
        accepts: Array.isArray(iface.accepts) ? iface.accepts.slice() : [],
        returns: Array.isArray(iface.returns) ? iface.returns.slice() : [],
      };
    });
  } else if (Array.isArray(fm.accepts) || Array.isArray(fm.returns)) {
    // legacy flat shape -> fold into interface 0
    out.interfaces = [{
      name: '',
      accepts: Array.isArray(fm.accepts) ? fm.accepts.slice() : [],
      returns: Array.isArray(fm.returns) ? fm.returns.slice() : [],
    }];
  }
  return out;
}

frontmatter__isFrontmatterEmpty.body:
export function isFrontmatterEmpty(fm: Frontmatter | undefined): boolean {
  if (!fm) return true;
  return !fm.name.trim()
    && !fm.description.trim()
    && fm.state.every((s) => !s.trim())
    && (fm.interfaces ?? []).every(isInterfaceEmpty);
}

frontmatter__pruneFrontmatter.body:
export function pruneFrontmatter(fm: Frontmatter): Frontmatter {
  return {
    name: fm.name.trim(),
    description: fm.description.trim(),
    state: fm.state.map((s) => s.trim()).filter(Boolean),
    interfaces: (fm.interfaces ?? [])
      .map((iface) => ({
        name: iface.name.trim(),
        accepts: iface.accepts.map((s) => s.trim()).filter(Boolean),
        returns: iface.returns.map((s) => s.trim()).filter(Boolean),
      }))
      .filter((iface) => !isInterfaceEmpty(iface)),
  };
}

frontmatter__frontmatterToMermaid.body:
export function frontmatterToMermaid(id: string, fm: Frontmatter | undefined): string {
  if (isFrontmatterEmpty(fm)) return '';
  const f = pruneFrontmatter(fm as Frontmatter);
  let out = '';
  if (f.name) out += `%% fm:meta ${id} name=${clean(f.name)}\n`;
  if (f.description) out += `%% fm:meta ${id} desc=${clean(f.description)}\n`;
  for (const s of f.state) out += `%% fm:meta ${id} state=${clean(s)}\n`;
  f.interfaces.forEach((iface, n) => {
    if (iface.name) out += `%% fm:meta ${id} i${n}.name=${clean(iface.name)}\n`;
    for (const a of iface.accepts) out += `%% fm:meta ${id} i${n}.accepts=${clean(a)}\n`;
    for (const r of iface.returns) out += `%% fm:meta ${id} i${n}.returns=${clean(r)}\n`;
  });
  return out;
}

frontmatter__matchFrontmatterLine.body:
export function matchFrontmatterLine(line: string):
  { id: string; key: string; value: string; iface?: number } | null {
  const m = line.match(
    /^%% fm:meta (\w+) (?:i(\d+)\.(name|accepts|returns)|(name|desc|state|accepts|returns))=(.*)$/,
  );
  if (!m) return null;
  const id = m[1];
  const value = m[5];
  if (m[2] !== undefined) {
    // interface-scoped line: i<N>.<subkey>
    return { id, key: m[3], value, iface: +m[2] };
  }
  const nodeKey = m[4];
  // legacy bare accepts/returns -> interface 0
  if (nodeKey === 'accepts' || nodeKey === 'returns') {
    return { id, key: nodeKey, value, iface: 0 };
  }
  return { id, key: nodeKey, value };
}

frontmatter__applyFrontmatterLine.body:
export function applyFrontmatterLine(
  acc: Record<string, Frontmatter>,
  parsed: { id: string; key: string; value: string; iface?: number },
): void {
  const fm = acc[parsed.id] ?? (acc[parsed.id] = emptyFrontmatter());
  const v = parsed.value;
  if (parsed.iface !== undefined) {
    const iface = ensureInterface(fm, parsed.iface);
    switch (parsed.key) {
      case 'name': iface.name = v; break;
      case 'accepts': iface.accepts.push(v); break;
      case 'returns': iface.returns.push(v); break;
    }
    return;
  }
  switch (parsed.key) {
    case 'name': fm.name = v; break;
    case 'desc': fm.description = v; break;
    case 'state': fm.state.push(v); break;
  }
}

frontmatter__TypeRef.body:
export interface TypeRef {
  /** optional variable/param name (left of the colon); '' when absent */
  varName: string;
  /** the type identity used for cross-referencing; not split further */
  type: string;
}

frontmatter__parseTypeRef.body:
export function parseTypeRef(raw: string): TypeRef {
  const s = raw.trim();
  const colon = s.indexOf(':');
  if (colon === -1) return { varName: '', type: s };
  return { varName: s.slice(0, colon).trim(), type: s.slice(colon + 1).trim() };
}

frontmatter__frontmatterTypeNames.body:
export function frontmatterTypeNames(fm: Frontmatter): string[] {
  const out: string[] = [];
  const push = (raw: string): void => {
    const t = parseTypeRef(raw).type;
    if (t) out.push(t);
  };
  if (fm.name.trim()) out.push(fm.name.trim());
  fm.state.forEach(push);
  for (const iface of fm.interfaces ?? []) {
    iface.accepts.forEach(push);
    iface.returns.forEach(push);
  }
  return out;
}

frontmatter__nodeUsesType.body:
export function nodeUsesType(fm: Frontmatter | undefined, type: string): boolean {
  if (!fm || !type) return false;
  return frontmatterTypeNames(fm).includes(type);
}

frontmatter__allTypeNames.body:
export function allTypeNames(nodes: Record<string, DiagramNode>): string[] {
  const set = new Set<string>();
  for (const id in nodes) {
    const fm = nodes[id].fm;
    if (fm) for (const t of frontmatterTypeNames(fm)) set.add(t);
  }
  return [...set].sort((a, b) => a.localeCompare(b));
}

history__History.body:
export interface History {
  stack: string[];
  i: number;
  max: number;
}

history__HistoryApi.body:
export interface HistoryApi {
  pushHistory: () => void;
  undo: () => void;
  redo: () => void;
  updateUndoButtons: () => void;
}

history__createHistory.body:
export function createHistory(): History {
  return { stack: [], i: -1, max: 80 };
}

history__initHistory.body:
export function initHistory(ctx: AppContext): HistoryApi {
  const { state, history } = ctx;
  const undoBtn = document.getElementById('undoBtn') as HTMLButtonElement;
  const redoBtn = document.getElementById('redoBtn') as HTMLButtonElement;

  function snapshot(): string {
    return JSON.stringify({ nodes: state.nodes, edges: state.edges, nid: state.nid, eid: state.eid, dir: state.dir });
  }

  function updateUndoButtons(): void {
    undoBtn.disabled = history.i <= 0;
    redoBtn.disabled = history.i >= history.stack.length - 1;
  }

  function pushHistory(): void {
    history.stack = history.stack.slice(0, history.i + 1);
    history.stack.push(snapshot());
    if (history.stack.length > history.max) history.stack.shift();
    history.i = history.stack.length - 1;
    updateUndoButtons();
    ctx.hooks.persist();
  }

  function restore(snap: string): void {
    const s = JSON.parse(snap);
    state.nodes = s.nodes; state.edges = s.edges; state.nid = s.nid; state.eid = s.eid;
    state.dir = s.dir || 'TD';
    state.sel.clear(); state.selEdge = null;
    ctx.hooks.render(); ctx.hooks.sync(); ctx.hooks.renderInspector();
  }

  function undo(): void {
    if (history.i <= 0) return;
    history.i--; restore(history.stack[history.i]);
    updateUndoButtons(); ctx.hooks.persist(); ctx.hooks.toast('Undo');
  }

  function redo(): void {
    if (history.i >= history.stack.length - 1) return;
    history.i++; restore(history.stack[history.i]);
    updateUndoButtons(); ctx.hooks.persist(); ctx.hooks.toast('Redo');
  }

  return { pushHistory, undo, redo, updateUndoButtons };
}

