export interface Issue {
  level: IssueLevel;
  /** stable machine code, e.g. 'dangling-parent', 'rt-edge-dropped' */
  code: string;
  message: string;
  /** node/edge ids the issue points at, for click-to-highlight later */
  ids?: string[];
