mermaid__fromMermaid.body:
export function fromMermaid(text: string): ParseResult {
  const nodes: Record<string, DiagramNode> = {};
  const edges: DiagramEdge[] = [];
  const meta: Record<string, { x: number; y: number; w: number; h: number; shape: ShapeKind; color: string | null }> = {};
  const orthoSet = new Set<string>();
  const bendMap = new Map<string, Point>();
  const labelPosMap = new Map<string, Point>();
  const roots: string[] = [];
  const groupStack: string[] = [];
  const fmAcc: Record<string, import('../core/types/types').Frontmatter> = {};
  const kindMap = new Map<string, import('../core/types/types').NodeKind>();
  const parentMap = new Map<string, string>();
  let maxN = 0, maxE = 0;
  let dir: FlowDir = 'TD';

  const bumpN = (id: string): void => { const n = +id.replace(/\D/g, ''); if (n > maxN) maxN = n; };
  const ensure = (id: string, label?: string, shape?: ShapeKind): void => {
    bumpN(id);
    if (!nodes[id]) {
      nodes[id] = { id, label: label ?? id, shape: shape ?? 'rect', color: PALETTE[0], x: 0, y: 0, w: 0, h: 0 };
    } else if (label) {
      nodes[id].label = label;
      if (shape) nodes[id].shape = shape;
    }
    if (groupStack.length) nodes[id].parent = groupStack[groupStack.length - 1];
  };

  text.split('\n').forEach((raw) => {
    const t = raw.trim();
    let m: RegExpMatchArray | null;

    if ((m = t.match(/^%% fm (\w+) (-?\d+) (-?\d+) (-?\d+) (-?\d+) (\w+) (#?\w+)/))) {
      meta[m[1]] = { x: +m[2], y: +m[3], w: +m[4], h: +m[5], shape: m[6] as ShapeKind, color: m[7] === 'null' ? null : m[7] };
      bumpN(m[1]); return;
    }
    const fmLine = matchFrontmatterLine(t);
    if (fmLine) { applyFrontmatterLine(fmAcc, fmLine); bumpN(fmLine.id); return; }
    if ((m = t.match(/^%% edge (\w+) ortho/))) { orthoSet.add(m[1]); return; }
    if ((m = t.match(/^%% edge (\w+) bend (-?\d+) (-?\d+)/))) { bendMap.set(m[1], { x: +m[2], y: +m[3] }); return; }
    if ((m = t.match(/^%% edge (\w+) labelpos (-?\d+) (-?\d+)/))) { labelPosMap.set(m[1], { x: +m[2], y: +m[3] }); return; }
    if ((m = t.match(/^%% root (\w+)/))) { roots.push(m[1]); bumpN(m[1]); return; }
    if ((m = t.match(/^%% kind (\w+) (\w+)/))) { kindMap.set(m[1], m[2] as import('../core/types/types').NodeKind); bumpN(m[1]); return; }
    if ((m = t.match(/^%% parent (\w+) (\w+)/))) { parentMap.set(m[1], m[2]); bumpN(m[1]); bumpN(m[2]); return; }
    if ((m = t.match(/^(?:flowchart|graph)\s+(TD|TB|BT|LR|RL)\b/i))) {
      const d = m[1].toUpperCase();
      dir = d === 'TB' ? 'TD' : (d as FlowDir);
      return;
    }
    if (t === 'end') { groupStack.pop(); return; }
    if (t.startsWith('%%') || /^(flowchart|graph)\b/.test(t)) return;

    if ((m = t.match(/^subgraph\s+(\w+)\s*\["?([^"\]]*)"?\]/))) { ensure(m[1], m[2], 'group'); groupStack.push(m[1]); return; }
    if ((m = t.match(/^(\w+)\(\["?([^"\)]*)"?\]\)/))) { ensure(m[1], m[2], 'stadium'); return; }
    if ((m = t.match(/^(\w+)\[\("?([^"\)]*)"?\)\]/))) { ensure(m[1], m[2], 'cylinder'); return; }
    if ((m = t.match(/^(\w+)\{\{"?([^"\}]*)"?\}\}/))) { ensure(m[1], m[2], 'hex'); return; }
    if ((m = t.match(/^(\w+)\(\("?([^"\)]*)"?\)\)/))) { ensure(m[1], m[2], 'circle'); return; }
    if ((m = t.match(/^(\w+)\{"?([^"\}]*)"?\}/))) { ensure(m[1], m[2], 'diamond'); return; }
    if ((m = t.match(/^(\w+)>"?([^"\]]*)"?\]/))) { ensure(m[1], m[2], 'note'); return; }
    if ((m = t.match(/^(\w+)\("?([^"\)]*)"?\)/))) { ensure(m[1], m[2], 'round'); return; }
    if ((m = t.match(/^(\w+)\["?([^"\]]*)"?\]/))) { ensure(m[1], m[2], 'rect'); return; }

    const em = t.match(/^(\w+)\s*(-\.->|==>|-->|---)\s*(?:\|([^|]*)\|)?\s*(\w+)/);
    if (em) {
      ensure(em[1]); ensure(em[4]);
      const style = em[2] === '-.->' ? 'dotted' : em[2] === '==>' ? 'thick' : 'solid';
      edges.push({ id: 'e' + (++maxE), from: em[1], to: em[4], label: (em[3] || '').trim(), style, routing: 'straight' });
    }
  });

  // apply metadata or auto-place
  let auto = 0;
  for (const id in nodes) {
    const n = nodes[id], md = meta[id];
    if (md) { Object.assign(n, md); }
    else {
      const d = DEFAULTS[n.shape] || DEFAULTS.rect;
      n.w = d.w; n.h = d.h;
      n.x = 80 + (auto % 4) * 200; n.y = 80 + Math.floor(auto / 4) * 130; auto++;
    }
    // attach frontmatter if any non-empty was parsed for this node
    if (fmAcc[id] && !isFrontmatterEmpty(fmAcc[id])) n.fm = fmAcc[id];
    // attach semantic kind if declared
    const k = kindMap.get(id);
    if (k) n.kind = k;
  }
  // apply containment (non-group parents) after all nodes exist
  parentMap.forEach((p, c) => { if (nodes[c] && nodes[p]) nodes[c].parent = p; });
  edges.forEach((e) => { if (orthoSet.has(e.id)) e.routing = 'ortho'; });
  edges.forEach((e) => {
    const bp = bendMap.get(e.id); if (bp) e.bend = bp;
    const lp = labelPosMap.get(e.id); if (lp) e.labelPos = lp;
  });
  const liveRoots = roots.filter((id) => nodes[id]);
  return { nodes, edges, nextN: maxN + 1, nextE: maxE + 1, dir, roots: liveRoots };
}

mermaid__applyText.body:
function applyText(): void {
    try {
      const r = fromMermaid(mmd.value);
      if (!Object.keys(r.nodes).length) { ctx.hooks.toast('No nodes parsed'); return; }
      state.nodes = r.nodes; state.edges = r.edges; state.nid = r.nextN; state.eid = r.nextE; state.dir = r.dir; state.roots = r.roots;
      selection.clearSel(); ctx.hooks.render(); sync(); ctx.hooks.pushHistory();
      ctx.hooks.toast('Applied');
    } catch { ctx.hooks.toast('Parse error'); }
  }

diffWorkspace__DiffWorkspaceApi.body:
export interface DiffWorkspaceApi {
  open: () => void;
  close: () => void;
}

diffWorkspace__initDiffWorkspace.body:
export function initDiffWorkspace(ctx: AppContext, deps: { mermaid: MermaidApi }): DiffWorkspaceApi {
  const $ = (id: string) => document.getElementById(id) as HTMLElement;
  const overlay = document.getElementById('diffOverlay');
  if (!overlay) return { open: () => {}, close: () => {} };

  const taBefore = $('diffBefore') as HTMLTextAreaElement;
  const taAfter = $('diffAfter') as HTMLTextAreaElement;
  const beforeMeta = $('diffBeforeMeta');
  const counts = $('diffCounts');
  const body = $('diffBody');

  let view: ViewId = 'list';
  let diff: MmdDiff | null = null;
  let beforeModel: ReturnType<typeof fromMermaid> | null = null;
  let afterModel: ReturnType<typeof fromMermaid> | null = null;

  /* ---- open: snapshot current diagram into "before" ---- */
  function open(): void {
    // Snapshot via re-parse path: serialize current model, that string IS the
    // frozen before. Re-parsing both sides identically = no false diffs.
    const snap = deps.mermaid.toMermaid();
    taBefore.value = snap;
    const n = Object.keys(ctx.state.nodes).length;
    const e = ctx.state.edges.length;
    beforeMeta.textContent = `· ${n} node${n !== 1 ? 's' : ''} · ${e} edge${e !== 1 ? 's' : ''}`;
    diff = null; beforeModel = null; afterModel = null;
    counts.innerHTML = '';
    body.innerHTML = '<div class="diff-hint">Paste a proposal above and click Compare.</div>';
    overlay!.classList.add('show');
    taAfter.focus();
  }

  function close(): void { overlay!.classList.remove('show'); }

  /* ---- compare: parse both, diff, render ---- */
  function compare(): void {
    let before, after;
    try { before = fromMermaid(taBefore.value); }
    catch (err) { return showError('before', err); }
    try { after = fromMermaid(taAfter.value); }
    catch (err) { return showError('after', err); }

    if (!taAfter.value.trim()) {
      body.innerHTML = '<div class="diff-empty">Paste a proposal in the “after” box first.</div>';
      counts.innerHTML = '';
      return;
    }

    beforeModel = before; afterModel = after;
    diff = diffModels(before, after);
    renderCounts(diff);
    renderActiveView();
  }

  function showError(side: string, err: unknown): void {
    const msg = err instanceof Error ? err.message : String(err);
    body.innerHTML = `<div class="diff-err">Parse error in “${side}” .mmd:\n${msg}</div>`;
    counts.innerHTML = '';
    diff = null;
  }

  function renderCounts(d: MmdDiff): void {
    const c = d.counts;
    const total = c.nAdd + c.nRem + c.nChg + c.eAdd + c.eRem;
    if (total === 0) {
      counts.innerHTML = '<span class="diff-badge zero">identical · no changes</span>';
      return;
    }
    const b = (cls: string, txt: string, n: number) => n ? `<span class="diff-badge ${cls}">${txt}</span>` : '';
    counts.innerHTML =
      b('add', `+${c.nAdd} nodes`, c.nAdd) +
      b('rem', `−${c.nRem} nodes`, c.nRem) +
      b('chg', `~${c.nChg} changed`, c.nChg) +
      b('add', `+${c.eAdd} edges`, c.eAdd) +
      b('rem', `−${c.eRem} edges`, c.eRem);
  }

  function renderActiveView(): void {
    if (!diff || !beforeModel || !afterModel) return;
    const arg = { diff, before: beforeModel, after: afterModel,
      beforeText: taBefore.value, afterText: taAfter.value };
    if (view === 'list') renderList(body, arg);
    else if (view === 'split') renderSplit(body, arg);
    else if (view === 'impact') renderImpact(body, arg);
    else if (view === 'overlay') renderOverlay(body, arg);
  }

  /* ---- apply: replace live model with the proposal (explicit confirm) ---- */
  function apply(): void {
    closeMenu();
    if (!taAfter.value.trim()) { ctx.hooks.toast('Nothing to apply'); return; }
    const c = diff?.counts;
    const summary = c
      ? `+${c.nAdd}/−${c.nRem} nodes, ~${c.nChg} changed, +${c.eAdd}/−${c.eRem} edges`
      : 'unreviewed changes';
    if (!confirm(`Overwrite the current diagram with this proposal?\n\n${summary}\n\nThis replaces what's on the canvas. You can undo (Ctrl/⌘+Z) after.`)) return;
    // route through the canonical apply path: write proposal into the mmd
    // textarea, then trigger applyText (the same path the Mermaid tab uses).
    ctx.dom.mmd.value = taAfter.value;
    deps.mermaid.applyText();
    close();
    ctx.hooks.toast('Proposal applied');
  }

  /* ---- actions menu ---- */
  const menu = $('diffMenu');
  function closeMenu(): void { menu.hidden = true; }
  $('diffMenuBtn').onclick = (e) => { e.stopPropagation(); menu.hidden = !menu.hidden; };
  document.addEventListener('click', () => { if (!menu.hidden) closeMenu(); });

  /* ---- resize handle: drag the input row taller/shorter ---- */
  (() => {
    const handle = $('diffResize');
    const inputs = $('diffInputs');
    if (!handle || !inputs) return;
    let dragging = false, startY = 0, startH = 0;
    const onMove = (ev: PointerEvent) => {
      if (!dragging) return;
      const h = Math.max(70, Math.min(window.innerHeight * 0.7, startH + (ev.clientY - startY)));
      inputs.style.height = h + 'px';
      inputs.style.maxHeight = 'none';
    };
    const onUp = () => {
      dragging = false; handle.classList.remove('dragging');
      window.removeEventListener('pointermove', onMove);
      window.removeEventListener('pointerup', onUp);
    };
    handle.addEventListener('pointerdown', (ev) => {
      ev.preventDefault();
      dragging = true; startY = ev.clientY; startH = inputs.getBoundingClientRect().height;
      handle.classList.add('dragging');
      window.addEventListener('pointermove', onMove);
      window.addEventListener('pointerup', onUp);
    });
  })();

  /* ---- wire DOM ---- */
  $('diffClose').onclick = close;
  $('diffCompare').onclick = compare;
  $('diffApply').onclick = apply;
  $('diffPaste').onclick = async () => {
    try { taAfter.value = await navigator.clipboard.readText(); compare(); }
    catch { ctx.hooks.toast('Clipboard read blocked — paste manually'); }
  };
  document.querySelectorAll<HTMLElement>('#diffTabs .diff-tab').forEach((btn) => {
    btn.onclick = () => {
      view = btn.dataset.view as ViewId;
      document.querySelectorAll('#diffTabs .diff-tab').forEach((b) => b.classList.toggle('active', b === btn));
      renderActiveView();
    };
  });
  overlay.addEventListener('keydown', (e) => { if (e.key === 'Escape') close(); });

  return { open, close };
}

