diffWorkspace__el.body:
export function el(tag: string, cls?: string, text?: string): HTMLElement {
  const e = document.createElement(tag);
  if (cls) e.className = cls;
  if (text != null) e.textContent = text;
  return e;
}

diffWorkspace__splitEdgeKey.body:
export function splitEdgeKey(k: string): { from: string; to: string; style: string } {
  const [pair, style] = k.split(':');
  const [from, to] = pair.split('->');
  return { from, to, style };
}

diffWorkspace__renderList.body:
export function renderList(host: HTMLElement, arg: ViewArg): void {
  const { diff, before, after } = arg;
  host.innerHTML = '';
  const root = el('div', 'dv-list');

  const total = diff.counts.nAdd + diff.counts.nRem + diff.counts.nChg + diff.counts.eAdd + diff.counts.eRem;
  if (total === 0) {
    root.appendChild(el('div', 'diff-empty', 'No changes. Proposal is identical to current.'));
    host.appendChild(root);
    return;
  }

  const section = (title: string, cls: string, n: number, rows: HTMLElement[]): void => {
    if (!n) return;
    const sec = el('div', 'dv-sec');
    const head = el('button', 'dv-sec-head');
    head.innerHTML = `<span class="dv-caret">▾</span><span class="dv-sec-title ${cls}">${title}</span><span class="dv-sec-n">${n}</span>`;
    const bodyEl = el('div', 'dv-sec-body');
    rows.forEach((r) => bodyEl.appendChild(r));
    head.onclick = () => {
      const open = bodyEl.style.display !== 'none';
      bodyEl.style.display = open ? 'none' : 'block';
      (head.querySelector('.dv-caret') as HTMLElement).textContent = open ? '▸' : '▾';
    };
    sec.appendChild(head); sec.appendChild(bodyEl);
    root.appendChild(sec);
  };

  // added nodes
  section('Added nodes', 'add', diff.counts.nAdd, diff.addedNodes.map((id) => {
    const n = after.nodes[id];
    return el('div', 'dv-row add', `+ ${id}  ·  ${n?.kind ?? n?.shape ?? ''}`);
  }));

  // removed nodes
  section('Removed nodes', 'rem', diff.counts.nRem, diff.removedNodes.map((id) => {
    const n = before.nodes[id];
    return el('div', 'dv-row rem', `− ${id}  ·  ${n?.kind ?? n?.shape ?? ''}`);
  }));

  // changed nodes (group by id)
  const byId = new Map<string, typeof diff.changedNodes>();
  diff.changedNodes.forEach((c) => {
    if (!byId.has(c.id)) byId.set(c.id, []);
    byId.get(c.id)!.push(c);
  });
  const changedRows: HTMLElement[] = [];
  byId.forEach((changes, id) => {
    const row = el('div', 'dv-row-block');
    row.appendChild(el('div', 'dv-row chg', `~ ${id}`));
    changes.forEach((c) => {
      const f = el('div', 'dv-field');
      f.innerHTML = `<span class="dv-field-name">${c.field}</span>`
        + `<div class="dv-before">− ${escapeHtml(c.before) || '<em>empty</em>'}</div>`
        + `<div class="dv-after">+ ${escapeHtml(c.after) || '<em>empty</em>'}</div>`;
      row.appendChild(f);
    });
    changedRows.push(row);
  });
  section('Changed nodes', 'chg', diff.counts.nChg, changedRows);

  // edges
  const edgeRows: HTMLElement[] = [];
  diff.addedEdges.forEach((k) => {
    const { from, to, style } = splitEdgeKey(k);
    edgeRows.push(el('div', 'dv-row add', `+ ${from} →|${style}| ${to}`));
  });
  diff.removedEdges.forEach((k) => {
    const { from, to, style } = splitEdgeKey(k);
    edgeRows.push(el('div', 'dv-row rem', `− ${from} →|${style}| ${to}`));
  });
  section('Edge changes', 'add', diff.counts.eAdd + diff.counts.eRem, edgeRows);

  host.appendChild(root);
}

diffWorkspace__renderSplit.body:
export function renderSplit(host: HTMLElement, arg: ViewArg): void {
  host.innerHTML = '';
  const a = arg.beforeText.replace(/\s+$/, '').split('\n');
  const b = arg.afterText.replace(/\s+$/, '').split('\n');
  const ops = lineDiff(a, b);

  const wrap = el('div', 'dv-split');
  const colL = el('div', 'dv-split-col');
  const colR = el('div', 'dv-split-col');
  colL.appendChild(el('div', 'dv-split-head', 'before · current'));
  colR.appendChild(el('div', 'dv-split-head', 'after · proposal'));

  for (const op of ops) {
    if (op.tag === 'eq') {
      colL.appendChild(lineRow('', op.left!, 'eq'));
      colR.appendChild(lineRow('', op.right!, 'eq'));
    } else if (op.tag === 'rem') {
      colL.appendChild(lineRow('−', op.left!, 'rem'));
      colR.appendChild(lineRow('', '', 'pad'));
    } else {
      colL.appendChild(lineRow('', '', 'pad'));
      colR.appendChild(lineRow('+', op.right!, 'add'));
    }
  }
  wrap.appendChild(colL); wrap.appendChild(colR);
  host.appendChild(wrap);
}

diffWorkspace__renderImpact.body:
export function renderImpact(host: HTMLElement, arg: ViewArg): void {
  const { diff, before, after } = arg;
  host.innerHTML = '';

  const total = diff.counts.nAdd + diff.counts.nRem + diff.counts.nChg + diff.counts.eAdd + diff.counts.eRem;
  if (total === 0) {
    host.appendChild(el('div', 'diff-empty', 'No changes — nothing impacted.'));
    return;
  }

  const hits = new Map<string, Hit>();
  const bump = (id: string, sev: Hit['sev'], reason: string): void => {
    let h = hits.get(id);
    if (!h) { h = { id, touch: 0, reasons: [], sev }; hits.set(id, h); }
    h.touch++;
    if (!h.reasons.includes(reason)) h.reasons.push(reason);
    // severity precedence: new/gone win over chg/edge
    if (sev === 'new' || sev === 'gone') h.sev = sev;
    else if (h.sev === 'edge' && sev === 'chg') h.sev = 'chg';
  };

  diff.addedNodes.forEach((id) => bump(id, 'new', 'new node'));
  diff.removedNodes.forEach((id) => bump(id, 'gone', 'removed node'));
  new Set(diff.changedNodes.map((c) => c.id)).forEach((id) => {
    const fields = diff.changedNodes.filter((c) => c.id === id).map((c) => c.field).join(', ');
    bump(id, 'chg', `changed: ${fields}`);
  });
  diff.addedEdges.forEach((k) => {
    const { from, to } = splitEdgeKey(k);
    bump(from, 'edge', '+outgoing edge'); bump(to, 'edge', '+incoming edge');
  });
  diff.removedEdges.forEach((k) => {
    const { from, to } = splitEdgeKey(k);
    bump(from, 'edge', '−outgoing edge'); bump(to, 'edge', '−incoming edge');
  });

  const list = [...hits.values()].sort((a, b) => b.touch - a.touch || a.id.localeCompare(b.id));
  const max = Math.max(1, ...list.map((h) => h.touch));

  const root = el('div', 'dv-impact');
  root.appendChild(el('div', 'dv-impact-cap', `blast radius · ${list.length} nodes touched · sorted by edges affected`));

  list.forEach((h) => {
    const exists = (h.id in before.nodes) || (h.id in after.nodes);
    const card = el('div', `dv-impact-row sev-${h.sev}`);
    const top = el('div', 'dv-impact-top');
    top.appendChild(el('span', 'dv-impact-id', h.id + (exists ? '' : ' (?)')));
    const barWrap = el('div', 'dv-impact-bar');
    const bar = el('div', `dv-impact-fill sev-${h.sev}`);
    bar.style.width = `${(h.touch / max) * 100}%`;
    barWrap.appendChild(bar);
    top.appendChild(barWrap);
    top.appendChild(el('span', 'dv-impact-n', `${h.touch}×`));
    card.appendChild(top);
    card.appendChild(el('div', 'dv-impact-why', h.reasons.join(' · ')));
    root.appendChild(card);
  });

  host.appendChild(root);
}

diffWorkspace__renderOverlay.body:
export function renderOverlay(host: HTMLElement, arg: ViewArg): void {
  const { diff, before, after } = arg;
  host.innerHTML = '';

  const total = diff.counts.nAdd + diff.counts.nRem + diff.counts.nChg + diff.counts.eAdd + diff.counts.eRem;
  if (total === 0) {
    host.appendChild(el('div', 'diff-empty', 'No changes to overlay.'));
    return;
  }

  const addedSet = new Set(diff.addedNodes);
  const removedSet = new Set(diff.removedNodes);
  const changedSet = new Set(diff.changedNodes.map((c) => c.id));
  const addedEdges = new Set(diff.addedEdges);

  // node lookup: after positions, plus removed nodes from before
  const place: Record<string, DiagramNode> = {};
  for (const id in after.nodes) place[id] = after.nodes[id];
  for (const id of removedSet) if (before.nodes[id]) place[id] = before.nodes[id];

  const ids = Object.keys(place);
  if (!ids.length) { host.appendChild(el('div', 'diff-empty', 'No positioned nodes to draw.')); return; }

  const dim = (n: DiagramNode) => ({ w: n.w || 160, h: n.h || 56 });
  const center = (n: DiagramNode) => { const d = dim(n); return { x: n.x + d.w / 2, y: n.y + d.h / 2 }; };

  // bounds helper over a set of ids
  const bounds = (set: string[]) => {
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    for (const id of set) {
      const n = place[id]; if (!n) continue;
      const d = dim(n);
      minX = Math.min(minX, n.x); minY = Math.min(minY, n.y);
      maxX = Math.max(maxX, n.x + d.w); maxY = Math.max(maxY, n.y + d.h);
    }
    if (minX === Infinity) return null;
    return { minX, minY, maxX, maxY };
  };

  // the "interesting" set = changed nodes + endpoints of changed edges
  const focusIds = new Set<string>([...addedSet, ...removedSet, ...changedSet]);
  [...diff.addedEdges, ...diff.removedEdges].forEach((k) => {
    const { from, to } = splitEdgeKey(k);
    if (place[from]) focusIds.add(from);
    if (place[to]) focusIds.add(to);
  });

  const allB = bounds(ids)!;
  const focusB = bounds([...focusIds]) ?? allB;

  /* ---- svg + pan/zoom state ---- */
  const svg = document.createElementNS(NS, 'svg');
  svg.setAttribute('class', 'dv-ovl-svg');
  svg.setAttribute('preserveAspectRatio', 'xMidYMid meet');

  const gridG = document.createElementNS(NS, 'g');  // background dots
  const sceneG = document.createElementNS(NS, 'g'); // nodes + edges
  svg.appendChild(gridG);
  svg.appendChild(sceneG);

  const mk = (parent: Element, tag: string, attrs: Record<string, string | number>): SVGElement => {
    const e = document.createElementNS(NS, tag);
    for (const k in attrs) e.setAttribute(k, String(attrs[k]));
    parent.appendChild(e);
    return e;
  };

  /* ---- draw scene (in world coords; transform handles zoom/pan) ---- */
  const drawEdge = (from: string, to: string, cls: string): void => {
    const a = place[from], b = place[to];
    if (!a || !b) return;
    const p1 = center(a), p2 = center(b);
    mk(sceneG, 'line', { x1: p1.x, y1: p1.y, x2: p2.x, y2: p2.y, class: `dv-ovl-edge ${cls}` });
  };
  for (const e of after.edges) {
    if (addedEdges.has(`${e.from}->${e.to}:${e.style}`)) continue;
    drawEdge(e.from, e.to, 'eq');
  }
  diff.addedEdges.forEach((k) => { const { from, to } = splitEdgeKey(k); drawEdge(from, to, 'add'); });
  diff.removedEdges.forEach((k) => { const { from, to } = splitEdgeKey(k); drawEdge(from, to, 'rem'); });

  for (const id of ids) {
    const n = place[id], d = dim(n);
    let cls = 'eq';
    if (addedSet.has(id)) cls = 'add';
    else if (removedSet.has(id)) cls = 'rem';
    else if (changedSet.has(id)) cls = 'chg';
    mk(sceneG, 'rect', { x: n.x, y: n.y, width: d.w, height: d.h, rx: 10, class: `dv-ovl-node ${cls}` });
    const c = center(n);
    const label = mk(sceneG, 'text', { x: c.x, y: c.y + 4, 'text-anchor': 'middle', class: `dv-ovl-label ${cls}` });
    label.textContent = id;
  }

  /* ---- pan/zoom: maintain a viewBox we mutate ---- */
  let vb = framed(focusB);
  applyVB();

  function framed(b: { minX: number; minY: number; maxX: number; maxY: number }) {
    const pad = 80;
    return { x: b.minX - pad, y: b.minY - pad, w: (b.maxX - b.minX) + pad * 2, h: (b.maxY - b.minY) + pad * 2 };
  }
  function applyVB(): void {
    svg.setAttribute('viewBox', `${vb.x} ${vb.y} ${vb.w} ${vb.h}`);
    // grid: tile dots across the visible viewBox in world space
    gridG.innerHTML = '';
    const step = 16;
    const x0 = Math.floor(vb.x / step) * step, y0 = Math.floor(vb.y / step) * step;
    // cap dot count so extreme zoom-out stays cheap
    const cols = Math.min(400, Math.ceil(vb.w / step) + 1);
    const rows = Math.min(400, Math.ceil(vb.h / step) + 1);
    for (let i = 0; i < cols; i++) for (let j = 0; j < rows; j++) {
      mk(gridG, 'circle', { cx: x0 + i * step, cy: y0 + j * step, r: 1.1, class: 'dv-ovl-dot' });
    }
  }

  // wheel zoom toward cursor
  svg.addEventListener('wheel', (ev) => {
    ev.preventDefault();
    const r = svg.getBoundingClientRect();
    const fx = (ev.clientX - r.left) / r.width;
    const fy = (ev.clientY - r.top) / r.height;
    const factor = ev.deltaY > 0 ? 1.12 : 1 / 1.12;
    const nw = Math.max(120, Math.min(40000, vb.w * factor));
    const nh = nw * (vb.h / vb.w);
    vb = { x: vb.x + (vb.w - nw) * fx, y: vb.y + (vb.h - nh) * fy, w: nw, h: nh };
    applyVB();
  }, { passive: false });

  // drag pan
  let dragging = false, lastX = 0, lastY = 0;
  svg.addEventListener('pointerdown', (ev) => {
    dragging = true; lastX = ev.clientX; lastY = ev.clientY;
    svg.setPointerCapture(ev.pointerId); svg.classList.add('grabbing');
  });
  svg.addEventListener('pointermove', (ev) => {
    if (!dragging) return;
    const r = svg.getBoundingClientRect();
    const dx = (ev.clientX - lastX) / r.width * vb.w;
    const dy = (ev.clientY - lastY) / r.height * vb.h;
    vb = { ...vb, x: vb.x - dx, y: vb.y - dy };
    lastX = ev.clientX; lastY = ev.clientY;
    applyVB();
  });
  const endDrag = () => { dragging = false; svg.classList.remove('grabbing'); };
  svg.addEventListener('pointerup', endDrag);
  svg.addEventListener('pointercancel', endDrag);

  /* ---- chrome ---- */
  const wrap = el('div', 'dv-ovl');
  const bar = el('div', 'dv-ovl-bar');
  const legend = el('div', 'dv-ovl-legend');
  legend.innerHTML =
    '<span class="dv-leg add">added</span>'
    + '<span class="dv-leg rem">removed</span>'
    + '<span class="dv-leg chg">changed</span>'
    + '<span class="dv-leg eq">unchanged</span>';
  const controls = el('div', 'dv-ovl-controls');
  const fitChanges = el('button', 'filebtn dv-mini', 'Fit changes');
  const fitAll = el('button', 'filebtn dv-mini', 'Fit all');
  const zoomHint = el('span', 'dv-ovl-hint', 'scroll = zoom · drag = pan');
  fitChanges.onclick = () => { vb = framed(focusB); applyVB(); };
  fitAll.onclick = () => { vb = framed(allB); applyVB(); };
  controls.appendChild(fitChanges); controls.appendChild(fitAll); controls.appendChild(zoomHint);
  bar.appendChild(legend); bar.appendChild(controls);

  wrap.appendChild(bar);
  wrap.appendChild(svg);
  host.appendChild(wrap);
}

inspectorFrontmatter__initInspectorFront.body:
export function initInspectorFrontmatter(ctx: AppContext) {
  /** Ensure the node has a frontmatter object to edit, return it. */
  function ensureFm(n: DiagramNode): Frontmatter {
    if (!n.fm) n.fm = emptyFrontmatter();
    return n.fm;
  }

  /** After any edit: drop the fm entirely if the user blanked everything. */
  function cleanupIfEmpty(n: DiagramNode): void {
    if (n.fm && isFrontmatterEmpty(n.fm)) n.fm = undefined;
  }

  /** A node-level state list (rows keyed only by item index). */
  function stateRowsHtml(items: string[]): string {
    return items.map((val, i) => `
      <div class="fm-listrow">
        <input class="fm-input" data-fmstate data-i="${i}" list="fmTypes" value="${esc(val)}" placeholder="${PLACEHOLDER.state}">
        <button class="fm-x" data-fmstatedel data-i="${i}" title="Remove">×</button>
      </div>`).join('');
  }

  /** One accepts/returns row inside interface `ifIdx`. */
  function ifaceListRowsHtml(ifIdx: number, key: IfaceKey, items: string[]): string {
    return items.map((val, i) => `
      <div class="fm-listrow">
        <input class="fm-input" data-iflist="${key}" data-if="${ifIdx}" data-i="${i}" list="fmTypes" value="${esc(val)}" placeholder="${PLACEHOLDER[key]}">
        <button class="fm-x" data-ifdel="${key}" data-if="${ifIdx}" data-i="${i}" title="Remove">×</button>
      </div>`).join('');
  }

  /** One interface block: name + accepts list + returns list + remove. */
  function ifaceBlockHtml(ifIdx: number, iface: { name: string; accepts: string[]; returns: string[] }): string {
    return `
      <div class="fm-iface" data-ifblock="${ifIdx}">
        <div class="fm-listhead fm-iface-head">
          <input class="fm-input fm-iface-name" data-ifname data-if="${ifIdx}" value="${esc(iface.name)}" placeholder="interface ${ifIdx + 1}">
          <button class="fm-x" data-deliface data-if="${ifIdx}" title="Remove interface">×</button>
        </div>
        ${IFACE_LISTS.map((key) => `
          <div class="fm-listgroup">
            <div class="fm-listhead"><label>${key}</label><button class="fm-add" data-ifadd="${key}" data-if="${ifIdx}">+ add</button></div>
            <div class="fm-list" data-iflistwrap="${key}" data-if="${ifIdx}">${ifaceListRowsHtml(ifIdx, key, iface[key])}</div>
          </div>`).join('')}
      </div>`;
  }

  /**
   * Render the whole frontmatter section into `host`. Re-rendered wholesale
   * only when list items / interfaces are added or removed; plain text edits
   * write to the model without re-render so focus is preserved (same as the
   * label field).
   */
  function render(host: HTMLElement, n: DiagramNode): void {
    const fm = n.fm;
    const present = fm && !isFrontmatterEmpty(fm);
    const interfaces = fm?.interfaces ?? [];
    const typeOptions = allTypeNames(ctx.state.nodes).map((t) => `<option value="${esc(t)}">`).join('');

    host.innerHTML = `
      <div class="insp-sec-title fm-sec-title">
        <span>Frontmatter</span>
        <span class="fm-hint">public interface</span>
      </div>
      <div class="field"><label>name</label><input id="fmName" class="fm-input" list="fmTypes" value="${esc(fm?.name ?? '')}" placeholder="${esc(n.label)}"></div>
      <div class="field"><label>description</label><textarea id="fmDesc" class="fm-input fm-area" rows="2" placeholder="what this does">${esc(fm?.description ?? '')}</textarea></div>
      <div class="fm-listgroup">
        <div class="fm-listhead"><label>state</label><button class="fm-add" data-fmstateadd>+ add</button></div>
        <div class="fm-list" data-fmstatewrap>${stateRowsHtml(fm?.state ?? [])}</div>
      </div>
      <div class="fm-ifaces">
        <div class="fm-listhead fm-ifaces-head"><label>interfaces</label><button class="fm-add" data-addiface>+ add interface</button></div>
        ${interfaces.map((iface, i) => ifaceBlockHtml(i, iface)).join('')}
      </div>
      ${present ? '<button class="filebtn fm-clear" id="fmClear">Clear frontmatter</button>' : ''}
      <datalist id="fmTypes">${typeOptions}</datalist>
    `;

    wire(host, n);
  }

  function wire(host: HTMLElement, n: DiagramNode): void {
    const reRender = (): void => render(host, n);
    const live = (): void => { ctx.hooks.render(); ctx.hooks.sync(); };
    const commit = (): void => { cleanupIfEmpty(n); ctx.hooks.pushHistory(); };

    // name
    const name = host.querySelector('#fmName') as HTMLInputElement;
    name.oninput = () => { ensureFm(n).name = name.value; live(); };
    name.onchange = commit;

    // description
    const desc = host.querySelector('#fmDesc') as HTMLTextAreaElement;
    desc.oninput = () => { ensureFm(n).description = desc.value; live(); };
    desc.onchange = commit;

    // node-level state: edits
    host.querySelectorAll('input[data-fmstate]').forEach((elRaw) => {
      const el = elRaw as HTMLInputElement;
      const i = +(el.dataset.i as string);
      el.oninput = () => { ensureFm(n).state[i] = el.value; live(); };
      el.onchange = commit;
    });
    // node-level state: add
    (host.querySelector('button[data-fmstateadd]') as HTMLButtonElement | null)?.addEventListener('click', () => {
      ensureFm(n).state.push('');
      reRender();
      const inputs = host.querySelector('[data-fmstatewrap]')?.querySelectorAll('input');
      (inputs?.[inputs.length - 1] as HTMLInputElement | undefined)?.focus();
      live();
    });
    // node-level state: remove
    host.querySelectorAll('button[data-fmstatedel]').forEach((btnRaw) => {
      const btn = btnRaw as HTMLButtonElement;
      btn.onclick = () => {
        const i = +(btn.dataset.i as string);
        n.fm?.state.splice(i, 1);
        cleanupIfEmpty(n);
        reRender();
        live(); ctx.hooks.pushHistory();
      };
    });

    // add an interface
    (host.querySelector('button[data-addiface]') as HTMLButtonElement | null)?.addEventListener('click', () => {
      ensureFm(n).interfaces.push(emptyInterface());
      reRender();
      // focus the new interface's name field
      const names = host.querySelectorAll('input[data-ifname]');
      (names[names.length - 1] as HTMLInputElement | undefined)?.focus();
      live();
    });

    // remove an interface
    host.querySelectorAll('button[data-deliface]').forEach((btnRaw) => {
      const btn = btnRaw as HTMLButtonElement;
      btn.onclick = () => {
        const ifIdx = +(btn.dataset.if as string);
        n.fm?.interfaces.splice(ifIdx, 1);
        cleanupIfEmpty(n);
        reRender();
        live(); ctx.hooks.pushHistory();
      };
    });

    // interface name edits
    host.querySelectorAll('input[data-ifname]').forEach((elRaw) => {
      const el = elRaw as HTMLInputElement;
      const ifIdx = +(el.dataset.if as string);
      el.oninput = () => { ensureFm(n).interfaces[ifIdx].name = el.value; live(); };
      el.onchange = commit;
    });

    // interface accepts/returns edits
    host.querySelectorAll('input[data-iflist]').forEach((elRaw) => {
      const el = elRaw as HTMLInputElement;
      const key = el.dataset.iflist as IfaceKey;
      const ifIdx = +(el.dataset.if as string);
      const i = +(el.dataset.i as string);
      el.oninput = () => { ensureFm(n).interfaces[ifIdx][key][i] = el.value; live(); };
      el.onchange = commit;
    });

    // add to an interface's accepts/returns
    host.querySelectorAll('button[data-ifadd]').forEach((btnRaw) => {
      const btn = btnRaw as HTMLButtonElement;
      btn.onclick = () => {
        const key = btn.dataset.ifadd as IfaceKey;
        const ifIdx = +(btn.dataset.if as string);
        ensureFm(n).interfaces[ifIdx][key].push('');
        reRender();
        const wrap = host.querySelector(`[data-iflistwrap="${key}"][data-if="${ifIdx}"]`);
        const inputs = wrap?.querySelectorAll('input');
        (inputs?.[inputs.length - 1] as HTMLInputElement | undefined)?.focus();
        live();
      };
    });

    // remove from an interface's accepts/returns
    host.querySelectorAll('button[data-ifdel]').forEach((btnRaw) => {
      const btn = btnRaw as HTMLButtonElement;
      btn.onclick = () => {
        const key = btn.dataset.ifdel as IfaceKey;
        const ifIdx = +(btn.dataset.if as string);
        const i = +(btn.dataset.i as string);
        n.fm?.interfaces[ifIdx]?.[key].splice(i, 1);
        cleanupIfEmpty(n);
        reRender();
        live(); ctx.hooks.pushHistory();
      };
    });

    // clear all frontmatter
    const clear = host.querySelector('#fmClear') as HTMLButtonElement | null;
    if (clear) {
      clear.onclick = () => {
        n.fm = undefined;
        reRender();
        live(); ctx.hooks.pushHistory();
      };
    }
  }

  return { renderFrontmatterSection: render };
}

