    function drawEdge(e: DiagramEdge, a: DiagramNode, b: DiagramNode): void {
      const [sa, sb] = bestSides(a, b);
      const p = portPos(a, sa), q = portPos(b, sb);
      const sel = state.selEdge === e.id;
      const onTrace = bothMatch(e);
